const languages = $input.item.json['Target Languages'].split(',').map(l => l.trim().toLowerCase());
const videoUrl = $input.item.json['Video URL'];
const brandName = $input.item.json['Project / Brand Name'];
const clipLimit = parseInt($input.item.json['Number of Clips Per Language']) || 3;

return languages.map(lang => ({
  json: {
    video_url: videoUrl,
    brand_name: brandName,
    target_lang: lang,
    clip_limit: clipLimit
  }
}));

const clips = $json.data.clips;

return clips.map(clip => ({
  json: {
    title: clip.title,
    export_link: clip.export_link,
    score: clip.score,
    tags: clip.tags,
    desc: clip.desc,
    begin_ms: clip.begin_ms,
    end_ms: clip.end_ms
  }
}));
